import { Email } from "../value-objects/email.js";
import type { UserCreateDTO } from "../dtos/user-create.js";
import { UserRole } from "@global-genius/database";
import { User as DBUser } from "@global-genius/database";

export class User {
  constructor(
    public email: string,
    public password: string,
    public role: UserRole = "STUDENT",
    public createdAt: Date = new Date(),
    public readonly id: string = crypto.randomUUID(),
  ) {}

  changeEmail(email: string) {
    this.email = Email.create(email).value;
  }

  changeRole(role: UserRole) {
    this.role = role;
  }

  static create(input: UserCreateDTO) {
    return new User(input.email, input.password);
  }

  static toJSON(dbUser: DBUser) {
    const { id, email, role, createdAt } = dbUser;
    return {
      id,
      email,
      role,
      createdAt,
    };
  }
}

